mapper.select:
SELECT id, user_id, profile_id, target_job_id, title, content_json, polished_content, created_at, updated_at
FROM reports
WHERE id = #{id}

SELECT id, user_id, profile_id, target_job_id, title, content_json, polished_content, created_at, updated_at
FROM reports
WHERE user_id = #{userId}
  AND profile_id = #{profileId}
ORDER BY created_at DESC, id DESC
